// Post-build: rewrite extensionless relative import/export specifiers in the
// compiled output so the package resolves under Node's native ESM loader.
//
// Why this exists: the client is generated by @hey-api/openapi-ts, whose output
// uses extensionless relative imports (e.g. `export * from './sdk.gen'`). tsc
// with `moduleResolution: Bundler` emits those specifiers verbatim, which Node
// ESM rejects (`ERR_MODULE_NOT_FOUND`) — so `import('@geolens/sdk')` crashed for
// any pure-Node consumer (caught by verify-published, broke npm 1.4.0). We can't
// hand-edit the generated src (the SDK drift gate checks generated-file equality)
// and hey-api 0.99.0 won't emit extensions, so fix the dist instead.
//
// Resolution is filesystem-based, not a regex guess: each relative specifier
// becomes `<spec>.js` if that file exists, else `<spec>/index.js` if that exists.
// Runs over both .js (runtime) and .d.ts (so NodeNext type consumers resolve too).
import { readFileSync, writeFileSync } from 'node:fs';
import { existsSync } from 'node:fs';
import { readdirSync } from 'node:fs';
import { dirname, resolve, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const DIST = resolve(dirname(fileURLToPath(import.meta.url)), '..', 'dist');

function walk(dir) {
  const out = [];
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const p = join(dir, entry.name);
    if (entry.isDirectory()) out.push(...walk(p));
    else if (entry.name.endsWith('.js') || entry.name.endsWith('.d.ts')) out.push(p);
  }
  return out;
}

// Matches the specifier in `from '...'`, `export ... from '...'`, and `import('...')`.
const SPEC_RE = /(\bfrom\s*|\bimport\s*\(\s*)(['"])(\.\.?\/[^'"]*)\2/g;

let filesChanged = 0;
let unresolved = 0;

for (const file of walk(DIST)) {
  const src = readFileSync(file, 'utf8');
  const fileDir = dirname(file);
  let changed = false;

  const next = src.replace(SPEC_RE, (match, lead, quote, spec) => {
    if (/\.(js|mjs|cjs|json)$/.test(spec)) return match; // already explicit
    const asFile = resolve(fileDir, `${spec}.js`);
    const asIndex = resolve(fileDir, spec, 'index.js');
    let fixed;
    if (existsSync(asFile)) fixed = `${spec}.js`;
    else if (existsSync(asIndex)) fixed = `${spec}/index.js`;
    else {
      console.warn(`fix-esm-extensions: could not resolve "${spec}" in ${file}`);
      unresolved++;
      return match;
    }
    changed = true;
    return `${lead}${quote}${fixed}${quote}`;
  });

  if (changed) {
    writeFileSync(file, next);
    filesChanged++;
  }
}

console.log(`fix-esm-extensions: rewrote specifiers in ${filesChanged} file(s)`);
if (unresolved > 0) {
  console.error(`fix-esm-extensions: ${unresolved} specifier(s) unresolved — failing`);
  process.exit(1);
}
